import type { Metadata } from "next";
import { Geist, Geist_Mono } from "next/font/google";
import "./globals.css";
import { getCurrentUser } from "@/lib/session";
import { getTeamMembers } from "@/lib/team";
import { setCurrentUser, clearCurrentUser } from "@/app/actions/session";

const geistSans = Geist({
  variable: "--font-geist-sans",
  subsets: ["latin"],
});

const geistMono = Geist_Mono({
  variable: "--font-geist-mono",
  subsets: ["latin"],
});

export const metadata: Metadata = {
  title: "Kudos",
  description: "Give and see team recognition",
};

export default async function RootLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  const currentUser = await getCurrentUser();
  const teamMembers = await getTeamMembers();

  return (
    <html lang="en">
      <body
        className={`${geistSans.variable} ${geistMono.variable} antialiased min-h-screen flex flex-col`}
      >
        <header className="border-b border-gray-200 bg-gray-50 px-4 py-3">
          <div className="max-w-4xl mx-auto flex items-center justify-between gap-4">
            <span className="font-semibold text-gray-800">Kudos</span>
            {currentUser ? (
              <div className="flex items-center gap-3">
                <span className="text-sm text-gray-600" aria-live="polite">
                  I am <strong>{currentUser.displayName ?? currentUser.name}</strong>
                </span>
                <form action={clearCurrentUser}>
                  <button
                    type="submit"
                    className="text-sm text-blue-600 hover:underline"
                  >
                    Change
                  </button>
                </form>
              </div>
            ) : (
              <form action={setCurrentUser} className="flex items-center gap-2">
                <label htmlFor="iam-select" className="text-sm text-gray-600 sr-only">
                  I am
                </label>
                <select
                  id="iam-select"
                  name="teamMemberId"
                  required
                  className="rounded border border-gray-300 px-3 py-1.5 text-sm"
                  aria-label="Select your identity"
                >
                  <option value="">I am…</option>
                  {teamMembers.map((m) => (
                    <option key={m.id} value={m.id}>
                      {m.displayName ?? m.name}
                    </option>
                  ))}
                </select>
                <button
                  type="submit"
                  className="rounded bg-gray-800 text-white px-3 py-1.5 text-sm hover:bg-gray-700"
                >
                  Continue
                </button>
              </form>
            )}
          </div>
        </header>
        <main className="flex-1">{children}</main>
      </body>
    </html>
  );
}
